var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"<color=#ffd34c>프리드웬 기관 소유 안전가옥</color>\\n총격전 발생 10분 전","JPN":"<color=#ffd34c>プリドウェン機関所有のセーフハウス</color>\\n銃撃戦発生の10分前","ENG":"<color=#ffd34c>Prydwen Institution-owned Safety House</color>\\n10 minutes before the shootout","TWN":"<color=#ffd34c>普利多溫機關的藏身處</color>\\n槍戰發生前10分鐘"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"아저씨들, 뭐 좀 나왔어?","JPN":"おっさんたち、何か出たか？","ENG":"Hey, you guys see anything?","TWN":"大叔們，有什麼發現嗎？"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L6_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"하하. 그랬으면 요원님 통신기가 정신없이 울렸겠지.","JPN":"はは。出てたら通信機が鳴りっぱなしだったろう。","ENG":"Haha. If we did, your comms would be pinging nonstop.","TWN":"哈哈，真有發現的話，你的通訊設備該響個不停了。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"책상에 피자 남은 거 있어. 먹고 나서 해.","JPN":"机に余ったピザがあるぞ。食べてからやれ。","ENG":"There's pizza left on the desk. Eat first.","TWN":"桌子上有剩下的披薩，吃完再繼續吧。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"뭐야, 이게. 골방에 처박혀서 맛없는 냉동 피자나 씹고.","JPN":"なんだよ、これ。小部屋に閉じこもってまずい冷凍ピザなんかかじってよ。","ENG":"Ugh... Eating frozen pizza in a stuffy room...","TWN":"這叫什麼事嘛，待在小屋裡吃著難以下嚥的冷凍披薩。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L11_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"그 <color=#ffd34c>교수</color>라는 인간, 정말 여기 나타나는 거 맞아?","JPN":"その<color=#ffd34c>教授</color>って人間、本当にここに現れるのか？","ENG":"The <color=#ffd34c>Professor</color>, are you sure he's going to be here?","TWN":"那個叫<color=#ffd34c>教授</color>的人，真的會出現在這裡嗎？"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"신뢰할 수 있는 정보처로부터 받은 소식이야.","JPN":"信頼できる情報元からのリークだ。","ENG":"It's from a highly credible source.","TWN":"消息來源是可靠的。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"그래도 조심해야지. 학부장 중에서도 특히 거물 취급 받는 놈이니까.","JPN":"それでも気をつけないと。学部長の中でも特に大物とされている奴だからな。","ENG":"Just be careful. He's considered one of the big fish of the deans.","TWN":"那也要小心才行。他在眾多學院院長中，也是大人物。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"카운터도 아니면서, 그 버넷 경도 은퇴하시기 전까지 결판을 못 낸 강적이거든.","JPN":"カウンターでもないのに、あのバーネット卿も引退するまで決着をつけられなかった強敵なんだ。","ENG":"He's not even a Counter, and Sir Burnett couldn't even take him down before he retired.","TWN":"明明不是制裁者，但在伯內特卿退休前，卻也沒能和他分出勝負。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"하. 나사 빠진 우리 할배가 뭐 그리 대단하다고.","JPN":"ハッ。うちの間抜けジジイのどこがすげえってのか、わけわかんねえ。","ENG":"*Sigh* What was so great about my crazy Grandpa anyway?","TWN":"唉，那個老掉牙的爺爺，有什麼了不起的。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L16_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"하하, 그 말 잠복 중인 친구들에게 하면 무척 섭섭해할 거야.","JPN":"はは、その言葉、張り込み中の奴らにするととても残念がるぞ。","ENG":"Haha! Your undercover friends will get upset if you say that in front of them.","TWN":"哈哈，你對潛伏中的同伴說這種話，可是會傷心的。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L18_1","type":"dialog","speaker":"MEMBER_PRYDWEN_NULL_NULL","text":{"KOREA":"중대장님, 나타났습니다! 인상착의도 일치합니다!","JPN":"中隊長、現れました！　人相書きとほぼ一致します！","ENG":"Sir! He's here! The description is a perfect match!","TWN":"中隊長，出現了！衣著打扮也一致！"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEMBER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L19_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"뭐? 카메라 당겨 봐, 어서!","JPN":"何？　ズームしろ、早く！","ENG":"What? Zoom in on the camera, quick!","TWN":"什麼？拉近鏡頭，快點！"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"이 인간이 그렇게 악랄한 놈이라고? 실물은 더 공붓벌레처럼 생겼는데?","JPN":"この人間がそんなあくどい奴なのか？　実物はもっとガリ勉っぽいけど。","ENG":"Are you sure it's him? He looks more of a bookworm than a vicious criminal, no?","TWN":"這個人真的是凶神惡煞的傢伙？本人看起來更像書呆子呢？"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L24_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"범죄 단체에게 대량 살상 무기의 알선, 테러 계획 지원, 국가 기밀 탈취……","JPN":"犯罪団体に大量の殺傷武器を斡旋、テロ計画の支援、国家機密の奪取……","ENG":"Providing weapons of mass destruction to criminal organizations, funding terrorist organizations, stealing national secrets...","TWN":"向犯罪組織介紹大量殺傷性武器，支援恐怖襲擊計畫，竊取國家機密……"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"그리고 지난번 그로니아 사태에 개입한 정황까지.","JPN":"それに、この間のグロニア事態に介入した状況まで。","ENG":"And even the circumstances surrounding his involvement in the recent Gronia incident.","TWN":"上次還插手了格羅尼亞事件。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"겉모습만 보고 얕보지 마. 저 노인에게 아티팩트 밀매는 소소한 취미야.","JPN":"見た目だけで判断すると痛い目にあうぞ。あの老人にとって、アーティファクトの密売はほんの趣味なんだ。","ENG":"Don't judge a book by its cover. That \\"bookworm\\" has a nasty hobby of smuggling in and out Artifacts.","TWN":"不能光看外表就小看他。對那個老人來說，走私人造神器只是一點小愛好。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"아니, 그렇게 설치고 다닐 동안 기관은 뭐 손가락만 빨고 있었대?","JPN":"いや、そうやって暗躍してる間に機関は何してたんだよ。","ENG":"So the Institution just stood there twiddling their thumbs while he did all of that?","TWN":"不是，他那樣到處閒悠的時候，機關就只是袖手旁觀嗎？"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"뒤집어서 생각해 봐. 기관이 개입해서 그나마 그 정도에서 끝난 거지.","JPN":"逆に考えてみろ。機関が介入したからその程度で終わったんだ。","ENG":"Think about it the other way around. It's because the Institution got involved that it stopped at there.","TWN":"你可以反過來想。正是因為機關有介入，他才會停留在那種程度。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"쳇…… 마음에 안 드네, 저 할배.","JPN":"チッ……あのジジイ、気に入らねえ。","ENG":"Tch... I don't like that gramps already.","TWN":"嘖……真讓人討厭，那個老頭。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L32_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"그래서 이대로 가만히 지켜만 보자고?","JPN":"で、このままじっと見てろってこと？","ENG":"So? Are we going to just watch him get away too?","TWN":"所以我們就這樣靜靜地看著嗎？"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"때를 기다려. 이번 작전 목표는 사살이 아니라 신병 확보야.","JPN":"時を待て。この作戦の目標は射殺じゃなくて身柄の確保だ。","ENG":"We wait. This operation is capturing him, not killing him.","TWN":"等待時機。這次的作戰目標是控制住嫌疑人而不是射殺。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"최근 합중국에서 학회의 동태가 심상치 않은 건 요원님도 알고 있겠지?","JPN":"最近合衆国で学会の動きが怪しいのは知ってるだろ？","ENG":"You heard about the recent unusual movements of the Society in the States, right?","TWN":"最近合眾國中學會的動態非比尋常，你也知道這件事吧？"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"저 자를 추궁하면 그놈들이 지금 무슨 짓을 꾸미는지 알아낼 수 있을 거다.","JPN":"あの者に問いただせば、そいつらが今何を企んでいるのかわかるはずだ。","ENG":"If we interrogate him, we'll know what they're up to.","TWN":"盤問那個人，就能查出他們現在在搞什麼鬼了。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"헷. 나도 알아. 그 얘긴 여기 올 때 홍차 폭탄에게 지긋지긋하게 들었다고.","JPN":"へっ。知ってるぜ。その話はここに来る時に紅茶爆弾から何回も聞かされた。","ENG":"Heh. I know that much. It was all Tea Bomb was talking about the way over here.","TWN":"嘿，我也知道。這些話在我來這兒之前就已經聽紅茶炸彈囉唆過無數遍了。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"응? 총소리잖아?","JPN":"ん？　銃声？","ENG":"Huh? Gunshots?","TWN":"嗯？槍聲？"},"stage":{"bg":"DORMITORY_1","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"잠복조, 보고하라. 무슨 일인가?","JPN":"潜伏組、報告しろ。何があった？","ENG":"Team, report. What's your status?","TWN":"埋伏組，報告，發生了什麼事？"},"stage":{"bg":"DORMITORY_1","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>긴급 사태 발생. 용병들이 염탐꾼을 접선 장소로 끌고 갔습니다.</color>","JPN":"<color=#ffd34c>緊急事態発生。傭兵たちがスパイを待ち合わせ場所に連れて行きました。</color>","ENG":"<color=#ffd34c>Code red! The mercenaries dragged some spies to the meeting point.</color>","TWN":"<color=#ffd34c>發生緊急情況。傭兵們把一個鬼鬼祟祟的傢伙抓到會合地點了。</color>"},"stage":{"bg":"DORMITORY_1","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L41_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"염탐꾼? 이 거래에 제 3자가 개입했다는 정황이 있었나?","JPN":"スパイ？　この取引に第三者が介入していたのか？","ENG":"Spies? Was there any evidence of a third party getting involved in the deal?","TWN":"鬼鬼祟祟的傢伙？難道這筆交易有第三方介入嗎？"},"stage":{"bg":"DORMITORY_1","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>사진을 보내 드리겠습니다. 얼굴 패턴을 확인해 주십시오.</color>","JPN":"<color=#ffd34c>写真を送ります。顔のパターンを確認してください。</color>","ENG":"<color=#ffd34c>I'm sending you a photo right now, sir. See if there's any facial match.</color>","TWN":"<color=#ffd34c>這就給你發照片，請確認臉部。</color>"},"stage":{"bg":"DORMITORY_1","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L45_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"이건…… 부학회장 아냐? 몽타주로 봤던 얼굴인데?","JPN":"これ……副学会長じゃねえ？　モンタージュで見た顔だぞ。","ENG":"That's... the Vice President, isn't it? I remember seeing her face on a sketch montage.","TWN":"這……不是副學會長嗎？我在剪輯裡看到過？"},"stage":{"bg":"DORMITORY_1","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L46_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"고등급 카운터가 저런 패거리들에게 맥없이 끌려갔다고?","JPN":"高ランクのカウンターが、あんな輩に簡単に引っ張られるか？","ENG":"A high-grade Counter getting dragged by some goons?","TWN":"高級制裁者毫無還手之力就被那夥人抓走了？"},"stage":{"bg":"DORMITORY_1","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L47_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"게다가 그 옆의 꼬마는…… 엘리시움의 복식이군. 무시할 만한 변수는 절대 아니야.","JPN":"それに、隣のガキは……エリシウムの服装だ。絶対無視できるような変数じゃない。","ENG":"And that kid next to her... She's wearing an Elysium uniform. This is not something we should take lightly.","TWN":"還有旁邊的小鬼……是愛樂組織的裝扮。這種變數絕對不可以忽略。"},"stage":{"bg":"DORMITORY_1","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L49_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"도청 장치 감도를 최대로 높여! 옷깃 스치는 소리 하나 놓쳐선 안 돼!","JPN":"盗聴器の感度を最大にしろ！　わずかな音も聞き逃すな！","ENG":"Maximize the wiretap's sensitivity! Enough to hear their breathing, all right?!","TWN":"把竊聽裝置的靈敏度調到最大！哪怕是擦過衣領的細小聲音都不可以錯過！"},"stage":{"bg":"DORMITORY_1","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"하아, 귀찮은 일에 나서는 건 영 질색인데…….","JPN":"はあ、面倒ごとはマジ勘弁してほしいんだけど……","ENG":"*Sigh...* I really don't want to get involved in this mess...","TWN":"唉，雖然我最討厭攪和麻煩事……"},"stage":{"bg":"DORMITORY_1","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"아저씨들은 한가하게 지켜봐도 되는 거 맞아? 거물이 둘이나 나타났는데?","JPN":"おっさんたちはのんびり見守ってていいのか？　大物が二人も現れたんだろ？","ENG":"Hey, are you sure we're supposed to just stay still? I mean, we've got 2 big targets over there.","TWN":"但是大叔們這樣悠閒地看著真的對嗎？出現了兩個大人物呢？"},"stage":{"bg":"DORMITORY_1","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"상정하지 않았던 상황이야. 그로니아 건만으로도 혼란스러운 마당에…….","JPN":"想定していなかった状況だ。グロニアの件だけでも混乱しているのに……","ENG":"This is unexpected. I'm as confused as I was with the Gronia case...","TWN":"這是我們意料之外的情況。光是格羅尼亞事件就夠亂了……"},"stage":{"bg":"DORMITORY_1","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>보고! 접선 장소에서 총격전 발생!</color>","JPN":"<color=#ffd34c>報告！　待ち合わせ場所で銃撃戦が発生！</color>","ENG":"<color=#ffd34c>Reporting! Gunshots fired at the meeting point!</color>","TWN":"<color=#ffd34c>報告！會合地點發生了槍戰！</color>"},"stage":{"bg":"DORMITORY_1","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MEMBER_PRYDWEN_NULL_NULL","text":{"KOREA":"윽……! 1번, 4번, 17번 도청기 파손됐습니다!","JPN":"うっ……！　1番、4番、17番の盗聴器が破壊されました！","ENG":"Ngh...! Wiretaps 1, 4, 17 are down!","TWN":"呃……！1號、4號、17號竊聽器損壞！"},"stage":{"bg":"DORMITORY_1","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEMBER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MEMBER_PRYDWEN_NULL_NULL","text":{"KOREA":"8번, 11번, 13번도 송신 불량!","JPN":"8番、11番、13番も送信不良！","ENG":"8, 11, and 13 are not transmitting!","TWN":"8號、11號、13號也訊號發送不良！"},"stage":{"bg":"DORMITORY_1","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEMBER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>내부 동태가 수상합니다. 계속 대기합니까?</color>","JPN":"<color=#ffd34c>内部の様子が妙です。このまま待機しますか？</color>","ENG":"<color=#ffd34c>Something's happening in there. Do we still standby?</color>","TWN":"<color=#ffd34c>內部動態可疑。要繼續待命嗎？</color>"},"stage":{"bg":"DORMITORY_1","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L8_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"젠장…….","JPN":"ちくしょう……","ENG":"Dammit...","TWN":"該死……"},"stage":{"bg":"DORMITORY_1","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"요원님, 갑작스럽지만 할 수 있겠나?","JPN":"突然だがやれるか？","ENG":"Agent, it's sudden, but can you do it?","TWN":"特務，事出突然，你自己能搞定嗎？"},"stage":{"bg":"DORMITORY_1","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"그런 걱정은 시동 거는 데 한나절씩 걸리는 영감탱이들한테나 하셔.","JPN":"そういうのはエンジンかけんのに半日もかかるジジイたちに言えよ。","ENG":"Tell that to the geezers who take ages to do anything.","TWN":"這種擔心，還是對上個廁所都要半天的老頭子們說吧。"},"stage":{"bg":"DORMITORY_1","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"어디 가서 시원하게 한 방 먹여 보실까?","JPN":"さて、派手に一発殴ってみますか！","ENG":"Let's go see what's happening over there.","TWN":"我好想找個地方痛快地給他們來一發？"},"stage":{"bg":"DORMITORY_1","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};